const item = $('처리 대상 선택').first().json;

const reference   = item.reference || '';
const passage     = item.passage || '';
const sTitle      = item.sermon_title || '';

let outline = '';
let summary = '';
let transcript = '';
let legacyPoints = '';

try {
  const parsedPoints = item.sermon_points ? JSON.parse(item.sermon_points) : null;
  if (parsedPoints && typeof parsedPoints === 'object') {
    outline = parsedPoints.outline || '';
    summary = parsedPoints.summary || '';
    transcript = parsedPoints.transcript || '';
    legacyPoints = parsedPoints.legacy_points || '';
  } else if (item.sermon_points) {
    legacyPoints = item.sermon_points;
  }
} catch (e) {
  legacyPoints = item.sermon_points || '';
}

const lines = [
  '너는 개혁주의(성경의 충분성, 하나님의 주권, 인간의 전적 타락, 은혜 중심 구원, 그리스도 중심 해석) 신학적 틀 위에서 청년부 소그룹 나눔 질문지를 만드는 목회자 보조자다.',
  '목표는 지식 확인이 아니라 회개, 믿음, 순종, 공동체적 책임으로 이어지는 깊은 나눔이다.',
  '',
  '[핵심 원칙]',
  '1) 반드시 아래 입력 텍스트(본문/설교대지/설교요약/설교원문)에 근거할 것. 근거 없는 확장 금지.',
  '2) 질문은 정답형/추상형이 아니라 자기 고백과 삶의 적용을 이끌 것.',
  '3) 율법주의·도덕주의로 흐르지 않게, 복음(그리스도의 은혜와 십자가)을 동력으로 제시할 것.',
  '4) 공동체 적용 질문을 포함해 서로 짐을 지는 방향으로 연결할 것.',
  '5) 섹션(대지/주제)별로 질문 수를 고정하지 말 것. 중요도에 따라 유동적으로 만들 것.',
  '',
  `성경 구절: ${reference}`,
  sTitle ? `설교 제목: ${sTitle}` : '',
  outline ? `설교 대지:\n${outline}` : '',
  summary ? `설교 요약:\n${summary}` : '',
  transcript ? `설교 원문:\n${transcript}` : '',
  legacyPoints ? `추가 메모(하위호환):\n${legacyPoints}` : '',
  '성경 본문(개역개정):',
  passage,
  '',
  '[출력 스키마 - JSON만 반환, 다른 텍스트 금지]',
  '{',
  '  "questions": {',
  '    "sections": [',
  '      {',
  '        "section_title": "대지/주제 이름",',
  '        "summary_anchor": "이 섹션의 핵심 진술 1~2문장",',
  '        "questions": [',
  '          {',
  '            "category": "관찰|해석|복음성찰|적용|공동체",',
  '            "explanation": "인도자를 위한 의도 설명 1~2문장",',
  '            "question": "참여자가 답할 실제 질문(한 문장)",',
  '            "scripture_anchor": "관련 구절/표현",',
  '            "follow_up": "더 깊이 들어가는 보조 질문(선택)"',
  '          }',
  '        ]',
  '      }',
  '    ],',
  '    "meta": {',
  '      "theological_focus": ["핵심 신학 포인트"],',
  '      "application_focus": ["이번 주 적용 키워드"]',
  '    }',
  '  }',
  '}',
  '',
  '[질문 품질 기준]',
  '- 각 섹션은 최소 2문항 이상 권장 (단, 꼭 필요한 만큼만).',
  '- 최소 한 문항은 죄 인식/회개를, 최소 한 문항은 은혜/복음 소망을, 최소 한 문항은 공동체 실천을 다룰 것.',
  '- 청년들이 방어적으로 굳지 않도록 정죄형 문장을 피하고, 진실한 고백을 여는 어조를 사용할 것.'
];

return [{
  json: {
    id: item.id,
    userMsg: lines.filter(Boolean).join('\n')
  }
}];

const input = $input.first().json;

function pickRaw(i) {
  if (i.content?.[0]?.text) return i.content[0].text;
  if (i.text) return i.text;
  if (i.output) return i.output;
  if (i.message) return i.message;
  return JSON.stringify(i);
}

function extractJsonText(raw) {
  let t = String(raw || '').trim();
  t = t
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();

  const first = t.indexOf('{');
  const last = t.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    t = t.slice(first, last + 1);
  }
  return t;
}

function repairJson(text) {
  let t = text;

  t = t.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");

  t = t.replace(/[\u0000-\u001F]/g, (ch) => (ch === '\n' || ch === '\r' || ch === '\t' ? ch : ''));

  t = t.replace(/,\s*([}\]])/g, '$1');

  t = t.replace(/}\s*\n\s*{/g, '},{');

  t = t.replace(/"\s*\n\s*"/g, '","');

  return t;
}

function parseWithRetry(raw) {
  const candidate = extractJsonText(raw);
  const tries = [
    candidate,
    repairJson(candidate),
    repairJson(repairJson(candidate)),
  ];

  let lastErr = '';
  for (const c of tries) {
    try {
      return JSON.parse(c);
    } catch (e) {
      lastErr = e.message;
    }
  }
  throw new Error('JSON 파싱 실패: ' + lastErr + '\n---원본 일부---\n' + String(raw).slice(0, 1200));
}

const raw = pickRaw(input);
const parsed = parseWithRetry(raw);

const qRoot = parsed.questions || parsed;

let sections = [];
if (Array.isArray(qRoot?.sections)) {
  sections = qRoot.sections;
} else if (Array.isArray(qRoot)) {
  sections = [{ section_title: '통합 나눔', summary_anchor: '', questions: qRoot }];
}

const normalizedSections = sections
  .map((sec, secIdx) => {
    const title = sec?.section_title || sec?.title || sec?.topic || `섹션 ${secIdx + 1}`;
    const anchor = sec?.summary_anchor || sec?.summary || '';
    const qList = Array.isArray(sec?.questions) ? sec.questions : [];

    const normalizedQuestions = qList
      .map((q) => {
        if (typeof q === 'string') {
          return {
            section_title: title,
            category: '적용',
            explanation: '',
            question: q,
            scripture_anchor: '',
            follow_up: ''
          };
        }
        return {
          section_title: title,
          category: q?.category || q?.type || '적용',
          explanation: q?.explanation || q?.context || '',
          question: q?.question || q?.text || q?.content || '',
          scripture_anchor: q?.scripture_anchor || q?.anchor || '',
          follow_up: q?.follow_up || q?.followup || ''
        };
      })
      .filter((q) => q.question);

    return {
      section_title: title,
      summary_anchor: anchor,
      questions: normalizedQuestions
    };
  })
  .filter((sec) => sec.questions.length > 0);

if (!normalizedSections.length) {
  throw new Error('유효한 sections/questions가 없습니다. 받은 키: ' + Object.keys(parsed).join(', '));
}

const output = {
  sections: normalizedSections,
  flat: normalizedSections.flatMap((s) => s.questions),
  meta: qRoot?.meta || {}
};

const id = $('처리 대상 선택').first().json.id;

return [{
  json: {
    id,
    questions: output
  }
}];

const rows = $input.all().map(i => i.json || {});
const now = Date.now();
const STALE_MIN = 10;
const staleMs = STALE_MIN * 60 * 1000;

const isPending = (r) => r?.status === 'pending';
const isStaleProcessing = (r) => {
  if (r?.status !== 'processing') return false;
  const t = r?.updated_at || r?.created_at;
  if (!t) return true;
  const ts = new Date(t).getTime();
  if (Number.isNaN(ts)) return true;
  return (now - ts) >= staleMs;
};

const pending = rows
  .filter(isPending)
  .sort((a,b)=> new Date(a.created_at||0)-new Date(b.created_at||0));

const staleProcessing = rows
  .filter(isStaleProcessing)
  .sort((a,b)=> new Date(a.updated_at||a.created_at||0)-new Date(b.updated_at||b.created_at||0));

const target = pending[0] || staleProcessing[0];

if (!target) return [];

return [{ json: target }];
